// This class will represent a single task in a to-do list
class Task {
    // Fields for task description and completion status
    String description;
    boolean isComplete;

    // Method to mark this task as done
    void markComplete() {
        isComplete = true;
    }

    // Method to print task status with a checkbox
    void printTask() {
        String checkbox = isComplete ? "[X]" : "[ ]";
        System.out.println(checkbox + " " + description);
    }
}
// Expected output when used:
// [ ] Buy groceries
// [X] Finish homework
